#include <bits/stdc++.h>
using namespace std;
struct que
{
    int pre,next;
};
que a[100005];
int main()
{
    int n,m,k,p;
    cin>>n;
    a[0].next=0;
    a[1].pre=0;
    a[1].next=-1;
    for(int i=2;i<=n;i++)
    {
        cin>>k>>p;
        if(p==0)
        {
            a[i].next=k;
            a[a[k].pre].next=i;
            a[i].pre=a[k].pre;
            a[k].pre=i;
        }
        else 
        {
            a[i].pre=k;
            a[a[k].next].pre=i;
            a[i].next=a[k].next;
            a[k].next=i;
        }
    }
    cin>>m;
    for(int i=1;i<=m;i++)
    {
        int x;
        cin>>x;
        if(a[x].pre!=-1||a[i].next!=-1)
        {
            a[a[x].pre].next=a[x].next;
            a[a[x].next].pre=a[x].pre;
            a[x].pre=-1;
            a[x].next=-1;
        }
    }
    for(int i=a[0].next;i!=-1;i=a[i].next)
    {
        cout<<i<<' ';
    }
    return 0;
}
